import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    { sender: "bot", text: "Hello 🌱 I’m here with you. Take your time." }
  ]);

  const [input, setInput] = useState("");
  const [hasGreeted, setHasGreeted] = useState(false);

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ================= HAPPY SONGS ================= */
    const happySongs = `
🎶 Telugu:
• Butta Bomma  
• Samajavaragamana  
• Inkem Inkem Inkem Kaavaale  

🎶 Hindi:
• Ilahi – Yeh Jawaani Hai Deewani  
• Love You Zindagi – Dear Zindagi  
• Phir Se Ud Chala  

🎶 English:
• Happy – Pharrell Williams  
• On Top of the World – Imagine Dragons  
• Good Life – OneRepublic
`;

    /* ================= GREETING ================= */
    if (!hasGreeted && ["hi", "hello", "hey", "hai"].includes(text)) {
      setHasGreeted(true);
      return "Hello 🌼 I’m glad you’re here. How are you feeling today?";
    }

    /* ================= SONG REQUEST (PRIORITY) ================= */
    if (text.includes("song") || text.includes("music")) {
      return (
        "Since you’re feeling positive, a little music might help you stay connected to that energy.\n\n" +
        happySongs +
        "\nTake a moment and enjoy what feels right for you 🌼"
      );
    }

    /* ================= HAPPY MOOD ================= */
    if (
      text.includes("happy") ||
      text.includes("great") ||
      text.includes("excited") ||
      text.includes("good today")
    ) {
      return (
        "That’s really nice to hear. I’m glad you’re noticing that feeling—" +
        "it’s important to pause and acknowledge moments like this."
      );
    }

    if (
      text.includes("light") ||
      text.includes("energetic") ||
      text.includes("free") ||
      text.includes("relaxed")
    ) {
      return (
        "That sense of lightness often comes when something inside feels settled or hopeful. " +
        "It sounds like your mind and body are enjoying this moment together."
      );
    }

    if (
      text.includes("positive") ||
      text.includes("everything is good") ||
      text.includes("feels nice")
    ) {
      return (
        "That’s wonderful. Positivity often reflects something meaningful—" +
        "an achievement, a connection, or even self-acceptance. " +
        "What do you think helped create this feeling?"
      );
    }

    if (
      text.includes("proud") ||
      text.includes("confidence")
    ) {
      return (
        "Feeling proud of yourself is powerful. It doesn’t mean you’re done growing—" +
        "it means you’re recognizing your effort and resilience. You’ve earned that."
      );
    }

    if (text.includes("thank")) {
      return (
        "You’re very welcome 🤍 I’m here with you. " +
        "Take your time—there’s no rush."
      );
    }

    /* ================= DEFAULT ================= */
    return (
      "Thank you for sharing 🤍\n\n" +
      "I’m here with you. Tell me more whenever you feel ready."
    );
  };

  const handleSend = () => {
    if (!input.trim()) return;

    setMessages([
      ...messages,
      { sender: "user", text: input },
      { sender: "bot", text: therapistReply(input) }
    ]);
    setInput("");
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, i) => (
          <div key={i} className={`message-group ${msg.sender}`}>
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>{msg.text}</div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type here when you're ready..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
